{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyM/h1zQhqVZml7OQYuTyb3Q"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"LGMTVDTIUeoP","executionInfo":{"status":"ok","timestamp":1775454328927,"user_tz":-330,"elapsed":44942,"user":{"displayName":"Pranav Yeolekar","userId":"17460622479383173652"}},"outputId":"2d0cbd31-debe-45ed-dad2-e305fe003329"},"outputs":[{"output_type":"stream","name":"stdout","text":["Collected 80 stories. Saved to data/trends_20260406.json\n"]}],"source":["# task1_data_collection.py\n","# TrendPulse - Task 1: Data Collection\n","# Author: <Your Name>\n","# Description: Fetch trending HackerNews stories, categorize them, and save to JSON.\n","\n","import requests\n","import time\n","import os\n","import json\n","from datetime import datetime\n","\n","# Define headers for API requests\n","headers = {\"User-Agent\": \"TrendPulse/1.0\"}\n","\n","# Define categories and keywords\n","categories = {\n","    \"technology\": [\"AI\", \"software\", \"tech\", \"code\", \"computer\", \"data\", \"cloud\", \"API\", \"GPU\", \"LLM\"],\n","    \"worldnews\": [\"war\", \"government\", \"country\", \"president\", \"election\", \"climate\", \"attack\", \"global\"],\n","    \"sports\": [\"NFL\", \"NBA\", \"FIFA\", \"sport\", \"game\", \"team\", \"player\", \"league\", \"championship\"],\n","    \"science\": [\"research\", \"study\", \"space\", \"physics\", \"biology\", \"discovery\", \"NASA\", \"genome\"],\n","    \"entertainment\": [\"movie\", \"film\", \"music\", \"Netflix\", \"game\", \"book\", \"show\", \"award\", \"streaming\"]\n","}\n","\n","# Step 1: Fetch top story IDs\n","try:\n","    top_ids = requests.get(\"https://hacker-news.firebaseio.com/v0/topstories.json\", headers=headers).json()\n","except Exception as e:\n","    print(\"Error fetching top stories:\", e)\n","    top_ids = []\n","\n","# Limit to first 500 IDs\n","top_ids = top_ids[:500]\n","\n","# Function to assign category based on title\n","def assign_category(title):\n","    if not title:\n","        return None\n","    title_lower = title.lower()\n","    for cat, keywords in categories.items():\n","        for kw in keywords:\n","            if kw.lower() in title_lower:\n","                return cat\n","    return None\n","\n","# Step 2: Fetch story details and categorize\n","collected = []\n","for cat in categories.keys():\n","    count = 0\n","    for story_id in top_ids:\n","        if count >= 25:  # limit per category\n","            break\n","        try:\n","            story = requests.get(f\"https://hacker-news.firebaseio.com/v0/item/{story_id}.json\", headers=headers).json()\n","            if not story or \"title\" not in story:\n","                continue\n","            category = assign_category(story.get(\"title\"))\n","            if category == cat:\n","                collected.append({\n","                    \"post_id\": story.get(\"id\"),\n","                    \"title\": story.get(\"title\"),\n","                    \"category\": category,\n","                    \"score\": story.get(\"score\"),\n","                    \"num_comments\": story.get(\"descendants\"),\n","                    \"author\": story.get(\"by\"),\n","                    \"collected_at\": datetime.now().strftime(\"%Y-%m-%d %H:%M:%S\")\n","                })\n","                count += 1\n","        except Exception as e:\n","            print(f\"Error fetching story {story_id}: {e}\")\n","            continue\n","    # Sleep 2 seconds between categories\n","    time.sleep(2)\n","\n","# Step 3: Save to JSON file\n","if not os.path.exists(\"data\"):\n","    os.makedirs(\"data\")\n","\n","filename = f\"data/trends_{datetime.now().strftime('%Y%m%d')}.json\"\n","with open(filename, \"w\", encoding=\"utf-8\") as f:\n","    json.dump(collected, f, indent=2)\n","\n","print(f\"Collected {len(collected)} stories. Saved to {filename}\")\n"]},{"cell_type":"code","source":["# task2_data_processing.py\n","# TrendPulse - Task 2: Data Processing\n","# Author: <Your Name>\n","# Description: Load JSON from Task 1, clean it, and save as CSV.\n","\n","import pandas as pd\n","import os\n","import json\n","\n","# Step 1: Load JSON file\n","# Find the latest trends JSON file in data/ folder\n","json_files = [f for f in os.listdir(\"data\") if f.startswith(\"trends_\") and f.endswith(\".json\")]\n","if not json_files:\n","    raise FileNotFoundError(\"No trends JSON file found in data/ folder.\")\n","\n","latest_file = sorted(json_files)[-1]  # pick the latest by filename\n","print(f\"Loading {latest_file}...\")\n","\n","df = pd.read_json(os.path.join(\"data\", latest_file))\n","print(f\"Loaded {len(df)} stories from {latest_file}\")\n","\n","# Step 2: Clean the Data\n","\n","# Remove duplicates by post_id\n","df = df.drop_duplicates(subset=\"post_id\")\n","print(f\"After removing duplicates: {len(df)}\")\n","\n","# Drop rows with missing critical fields\n","df = df.dropna(subset=[\"post_id\", \"title\", \"score\"])\n","print(f\"After removing nulls: {len(df)}\")\n","\n","# Ensure score and num_comments are integers\n","df[\"score\"] = df[\"score\"].astype(int)\n","df[\"num_comments\"] = df[\"num_comments\"].fillna(0).astype(int)\n","\n","# Remove low-quality stories (score < 5)\n","df = df[df[\"score\"] >= 5]\n","print(f\"After removing low scores: {len(df)}\")\n","\n","# Strip whitespace from titles\n","df[\"title\"] = df[\"title\"].str.strip()\n","\n","# Step 3: Save as CSV\n","output_file = \"data/trends_clean.csv\"\n","df.to_csv(output_file, index=False)\n","print(f\"Saved {len(df)} rows to {output_file}\")\n","\n","# Print summary: stories per category\n","summary = df[\"category\"].value_counts()\n","print(\"\\nStories per category:\")\n","print(summary)\n"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"ezKtAgNHVJsy","executionInfo":{"status":"ok","timestamp":1775454839461,"user_tz":-330,"elapsed":700,"user":{"displayName":"Pranav Yeolekar","userId":"17460622479383173652"}},"outputId":"34faa77c-c143-4994-b753-a854ea9fd31c"},"execution_count":null,"outputs":[{"output_type":"stream","name":"stdout","text":["Loading trends_20260406.json...\n","Loaded 80 stories from trends_20260406.json\n","After removing duplicates: 80\n","After removing nulls: 80\n","After removing low scores: 77\n","Saved 77 rows to data/trends_clean.csv\n","\n","Stories per category:\n","category\n","technology       24\n","entertainment    24\n","science          11\n","worldnews        10\n","sports            8\n","Name: count, dtype: int64\n"]}]},{"cell_type":"code","source":["# task3_analysis.py\n","# TrendPulse - Task 3: Analysis with Pandas & NumPy\n","# Author: <Your Name>\n","# Description: Load cleaned CSV, analyze with Pandas/NumPy, add new columns, save results.\n","\n","import pandas as pd\n","import numpy as np\n","import os\n","\n","# Step 1: Load and Explore\n","csv_file = \"data/trends_clean.csv\"\n","if not os.path.exists(csv_file):\n","    raise FileNotFoundError(\"Clean CSV file not found. Run Task 2 first.\")\n","\n","df = pd.read_csv(csv_file)\n","print(f\"Loaded data: {df.shape}\\n\")\n","\n","print(\"First 5 rows:\")\n","print(df.head())\n","\n","# Average score and comments\n","avg_score = df[\"score\"].mean()\n","avg_comments = df[\"num_comments\"].mean()\n","print(f\"\\nAverage score   : {avg_score:.2f}\")\n","print(f\"Average comments: {avg_comments:.2f}\")\n","\n","# Step 2: Basic Analysis with NumPy\n","scores = df[\"score\"].values\n","comments = df[\"num_comments\"].values\n","\n","print(\"\\n--- NumPy Stats ---\")\n","print(f\"Mean score   : {np.mean(scores):.2f}\")\n","print(f\"Median score : {np.median(scores):.2f}\")\n","print(f\"Std deviation: {np.std(scores):.2f}\")\n","print(f\"Max score    : {np.max(scores)}\")\n","print(f\"Min score    : {np.min(scores)}\")\n","\n","# Category with most stories\n","most_category = df[\"category\"].value_counts().idxmax()\n","most_count = df[\"category\"].value_counts().max()\n","print(f\"\\nMost stories in: {most_category} ({most_count} stories)\")\n","\n","# Story with most comments\n","max_comments_idx = np.argmax(comments)\n","print(f\"Most commented story: \\\"{df.iloc[max_comments_idx]['title']}\\\" — {df.iloc[max_comments_idx]['num_comments']} comments\")\n","\n","# Step 3: Add New Columns\n","df[\"engagement\"] = df[\"num_comments\"] / (df[\"score\"] + 1)\n","df[\"is_popular\"] = df[\"score\"] > avg_score\n","\n","# Step 4: Save the Result\n","output_file = \"data/trends_analysed.csv\"\n","df.to_csv(output_file, index=False)\n","print(f\"\\nSaved to {output_file}\")\n"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"8WYYw_rqWt5l","executionInfo":{"status":"ok","timestamp":1775455005780,"user_tz":-330,"elapsed":75,"user":{"displayName":"Pranav Yeolekar","userId":"17460622479383173652"}},"outputId":"c2985f41-e055-42f8-9c5b-0fbce9ea8775"},"execution_count":null,"outputs":[{"output_type":"stream","name":"stdout","text":["Loaded data: (77, 7)\n","\n","First 5 rows:\n","    post_id                                              title    category  \\\n","0  47655408  Show HN: I built a tiny LLM to demystify how l...  technology   \n","1  47655329  Copilot is 'for entertainment purposes only', ...  technology   \n","2  47652007  Show HN: Real-time AI (audio/video in, voice o...  technology   \n","3  47655367  Show HN: Gemma Gem – AI model embedded in a br...  technology   \n","4  47636765      Endian wars and anti-portability: this again?  technology   \n","\n","   score  num_comments      author         collected_at  \n","0    237            17  armanified  2026-04-06 05:44:44  \n","1    118            22   airstrike  2026-04-06 05:44:44  \n","2      9             1      karimf  2026-04-06 05:44:44  \n","3     38             5    ikessler  2026-04-06 05:44:44  \n","4     39            38     awilfox  2026-04-06 05:44:44  \n","\n","Average score   : 179.64\n","Average comments: 83.45\n","\n","--- NumPy Stats ---\n","Mean score   : 179.64\n","Median score : 91.00\n","Std deviation: 247.07\n","Max score    : 1074\n","Min score    : 5\n","\n","Most stories in: technology (24 stories)\n","Most commented story: \"Tell HN: Anthropic no longer allowing Claude Code subscriptions to use OpenClaw\" — 821 comments\n","\n","Saved to data/trends_analysed.csv\n"]}]},{"cell_type":"code","source":["# task4_visualization.py\n","# TrendPulse - Task 4: Visualizations\n","# Author: <Your Name>\n","# Description: Create charts from analysed data and save as PNGs.\n","\n","import pandas as pd\n","import matplotlib.pyplot as plt\n","import os\n","\n","# Step 1: Setup\n","csv_file = \"data/trends_analysed.csv\"\n","if not os.path.exists(csv_file):\n","    raise FileNotFoundError(\"Analysed CSV file not found. Run Task 3 first.\")\n","\n","df = pd.read_csv(csv_file)\n","\n","# Create outputs folder if not exists\n","if not os.path.exists(\"outputs\"):\n","    os.makedirs(\"outputs\")\n","\n","# Step 2: Chart 1 — Top 10 Stories by Score\n","top10 = df.nlargest(10, \"score\")[[\"title\", \"score\"]]\n","# Shorten titles > 50 chars\n","top10[\"title\"] = top10[\"title\"].apply(lambda x: x[:47] + \"...\" if len(x) > 50 else x)\n","\n","plt.figure(figsize=(10,6))\n","plt.barh(top10[\"title\"], top10[\"score\"], color=\"skyblue\")\n","plt.xlabel(\"Score\")\n","plt.ylabel(\"Story Title\")\n","plt.title(\"Top 10 Stories by Score\")\n","plt.gca().invert_yaxis()  # highest score at top\n","plt.tight_layout()\n","plt.savefig(\"outputs/chart1_top_stories.png\")\n","plt.close()\n","\n","# Step 3: Chart 2 — Stories per Category\n","category_counts = df[\"category\"].value_counts()\n","\n","plt.figure(figsize=(8,6))\n","category_counts.plot(kind=\"bar\", color=[\"#FF9999\",\"#66B2FF\",\"#99FF99\",\"#FFCC99\",\"#C299FF\"])\n","plt.xlabel(\"Category\")\n","plt.ylabel(\"Number of Stories\")\n","plt.title(\"Stories per Category\")\n","plt.tight_layout()\n","plt.savefig(\"outputs/chart2_categories.png\")\n","plt.close()\n","\n","# Step 4: Chart 3 — Score vs Comments Scatter\n","plt.figure(figsize=(8,6))\n","colors = df[\"is_popular\"].map({True: \"green\", False: \"red\"})\n","plt.scatter(df[\"score\"], df[\"num_comments\"], c=colors, alpha=0.6)\n","plt.xlabel(\"Score\")\n","plt.ylabel(\"Number of Comments\")\n","plt.title(\"Score vs Comments\")\n","plt.legend(handles=[\n","    plt.Line2D([0],[0], marker='o', color='w', label='Popular', markerfacecolor='green', markersize=8),\n","    plt.Line2D([0],[0], marker='o', color='w', label='Not Popular', markerfacecolor='red', markersize=8)\n","])\n","plt.tight_layout()\n","plt.savefig(\"outputs/chart3_scatter.png\")\n","plt.close()\n","\n","# Bonus: Dashboard combining all charts\n","fig, axes = plt.subplots(1, 3, figsize=(20,6))\n","\n","# Chart 1 in dashboard\n","axes[0].barh(top10[\"title\"], top10[\"score\"], color=\"skyblue\")\n","axes[0].set_title(\"Top 10 Stories by Score\")\n","axes[0].set_xlabel(\"Score\")\n","axes[0].invert_yaxis()\n","\n","# Chart 2 in dashboard\n","axes[1].bar(category_counts.index, category_counts.values, color=[\"#FF9999\",\"#66B2FF\",\"#99FF99\",\"#FFCC99\",\"#C299FF\"])\n","axes[1].set_title(\"Stories per Category\")\n","axes[1].set_xlabel(\"Category\")\n","axes[1].set_ylabel(\"Count\")\n","\n","# Chart 3 in dashboard\n","axes[2].scatter(df[\"score\"], df[\"num_comments\"], c=colors, alpha=0.6)\n","axes[2].set_title(\"Score vs Comments\")\n","axes[2].set_xlabel(\"Score\")\n","axes[2].set_ylabel(\"Comments\")\n","\n","fig.suptitle(\"TrendPulse Dashboard\", fontsize=16)\n","plt.tight_layout()\n","plt.savefig(\"outputs/dashboard.png\")\n","plt.close()\n","\n","print(\"Charts saved in outputs/ folder:\")\n","print(\" - chart1_top_stories.png\")\n","print(\" - chart2_categories.png\")\n","print(\" - chart3_scatter.png\")\n","print(\" - dashboard.png (bonus)\")\n"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"B3HAkylSXWnS","executionInfo":{"status":"ok","timestamp":1775455099717,"user_tz":-330,"elapsed":4529,"user":{"displayName":"Pranav Yeolekar","userId":"17460622479383173652"}},"outputId":"b12fd92f-99b5-43d8-9b92-c62666937dd6"},"execution_count":null,"outputs":[{"output_type":"stream","name":"stdout","text":["Charts saved in outputs/ folder:\n"," - chart1_top_stories.png\n"," - chart2_categories.png\n"," - chart3_scatter.png\n"," - dashboard.png (bonus)\n"]}]},{"cell_type":"code","source":[],"metadata":{"id":"WWFh-RFvXsfz"},"execution_count":null,"outputs":[]}]}